INSERT INTO guides (title, category, subcategory, summary, content, is_premium, status, updated_by, updated_at) VALUES
('전표 작성 완벽 가이드 — 차변·대변부터 분개까지', '세무회계', '전표/결산',
 '회계 초보자도 바로 쓸 수 있는 전표 작성법. 입금·출금·대체 전표 구분과 분개 예시를 총망라했습니다.',
 E'## 전표란 무엇인가?\n\n전표는 거래 발생 시 회계 처리를 기록하는 원시 증빙입니다.\n\n### 전표의 3종류\n| 구분 | 사용 시점 | 예시 |\n|------|-----------|------|\n| 입금 전표 | 현금 수입 | 매출 대금 수령 |\n| 출금 전표 | 현금 지출 | 경비 지급 |\n| 대체 전표 | 현금 미개입 | 외상매출금 회수 |\n\n### 분개 기본 원칙\n> 차변(DR) = 대변(CR) — 반드시 일치해야 합니다.\n\n**예시: 문구 구입 50,000원 (현금)**\n- 차변: 소모품비 50,000\n- 대변: 현금 50,000\n\n### 자주 쓰는 계정과목\n- **매출채권** — 외상 판매\n- **미지급금** — 외상 구입\n- **선급금** — 계약금 지급\n- **선수금** — 계약금 수령\n\n### 전표 작성 체크리스트\n- [ ] 거래 일자 정확히 기재\n- [ ] 증빙 번호 매핑\n- [ ] 차변·대변 금액 일치\n- [ ] 적요 간결하게 작성\n- [ ] 결재자 날인 확인',
 false, 'published', 'lsol3264@gmail.com', NOW()),

('월말 결산 8단계 체크리스트 — 한 번에 완성하는 법', '세무회계', '전표/결산',
 '매월 반복되는 결산 업무를 실수 없이 마감하는 순서와 체크포인트를 정리했습니다.',
 E'## 월말 결산이란?\n\n한 달 동안 발생한 모든 거래를 마감하고 재무 보고서를 작성하는 과정입니다.\n\n### 결산 8단계\n\n#### 1단계: 증빙 수집 및 정리 (월말 -3일)\n- [ ] 세금계산서 합계 확인\n- [ ] 카드 사용내역 취합\n- [ ] 현금영수증 수집\n\n#### 2단계: 전표 입력 마감 (월말 -2일)\n- [ ] 미입력 거래 전표 일괄 작성\n- [ ] 급여 전표 생성\n- [ ] 고정비 정기 전표 처리\n\n#### 3단계: 잔액 검증 (월말 당일)\n- [ ] 현금 시재 실사\n- [ ] 은행 잔액 대사\n- [ ] 외상매출금·미수금 확인\n\n#### 4단계: 감가상각 처리\n- [ ] 고정자산 대장 업데이트\n- [ ] 월할 상각 전표 작성\n\n#### 5단계: 선급·선수 배분\n- [ ] 선급비용 당기 귀속분 정리\n- [ ] 선수수익 실현분 인식\n\n#### 6단계: 대손충당금 검토\n- [ ] 3개월 이상 미회수 채권 확인\n- [ ] 대손충당금 적립 여부 검토\n\n#### 7단계: 시산표 작성\n- [ ] 합계잔액시산표 출력\n- [ ] 차대 불일치 항목 수정\n\n#### 8단계: 보고서 제출\n- [ ] 손익계산서 전월 비교\n- [ ] 부서별 경비 보고서\n- [ ] 대표 보고용 요약본 작성\n\n> 💡 결산은 정확성이 속도보다 중요합니다. 단계별로 확인 후 진행하세요.',
 false, 'published', 'lsol3264@gmail.com', NOW()),

